  ('customs-41d95f20-moex-00028', 'customs-41d95f20', 'customs-41d95f20-moex-114-9b7ab1bb', 'sub-customs-41d95f20-02', NULL, 'essay', '甲受乙之脅迫，於民國 110 年 2 月間，將其珍愛收藏之 A 古董花瓶以遠
低於市價之價格出賣於善意之丙，並當場交付 A花瓶於丙。甲當時深覺委
屈，但因懾於乙之勢力，一直不敢向丙表示。嗣 113 年間，乙因犯強盜案
件入獄服刑，甲才鼓起勇氣，向丙表白當年遭乙脅迫之情事，並向丙請求
返還 A花瓶，丙抗辯事情已過了很久，事過境遷，拒絕甲之請求。試問甲
丙間主張，孰有理由？請分別論述之。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:12+00:00", "source_pdf_sha1": "42ff8c8afb7b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "103", "s": "0401", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "關稅法務"}'::jsonb, NULL),
  ('customs-41d95f20-moex-00029', 'customs-41d95f20', 'customs-41d95f20-moex-114-9b7ab1bb', 'sub-customs-41d95f20-02', NULL, 'essay', '甲 15 歲國中畢業，因未有升學計畫，乃以自己零用錢，購買一輛A重型
機車，並未經其法定代理人乙之同意下，受僱於丙便當店，從事便當外送
業務。某日，甲騎乘 A機車，穿著印有丙便當店之制服，於載送便當前往
客戶途中，於紅燈停等時，巧遇昔日情敵丁，甲因妒火中燒，乃下車毆打
丁，導致丁受重傷，住院花費新臺幣 10 萬元。試問丁得否向甲、乙、丙
請求損害賠償？請分別論述之。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:12+00:00", "source_pdf_sha1": "42ff8c8afb7b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "103", "s": "0401", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "關稅法務"}'::jsonb, NULL)
